/// ECMA §17.5.1.9/.10, Annex A CT_SmartTagRun, MS-OI29500 §2.1.187 — on re-nest
/// the serializer must emit smartTagPr BEFORE the wrapped run content.
#[test]
fn smarttag_pr_renest_precedes_run_content() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Stock: </w:t></w:r><w:smartTag w:uri="urn:schemas-microsoft-com:office:smarttags" w:element="stockticker"><w:smartTagPr><w:attr w:uri="urn:schemas-microsoft-com:office:office" w:name="sym" w:val="CNTS"/></w:smartTagPr><w:r><w:t>CNTS</w:t></w:r></w:smartTag></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // xmlRegex `<w:smartTag\b[^>]*><w:smartTagPr>.*?</w:smartTagPr><w:r>`
    // translated to an ordering-aware contains check (regex crate is not a dev
    // dependency of this crate): smartTag open, then smartTagPr open, then
    // smartTagPr close, then a run open, in that sequence.
    if let Err(detail) = ordered_contains(
        &xml,
        &["<w:smartTag", "<w:smartTagPr>", "</w:smartTagPr>", "<w:r>"],
    ) {
        panic!(
            "ECMA Annex A CT_SmartTagRun = (smartTagPr?, EG_PContent*): the re-nest serializer must place smartTagPr immediately after the opening smartTag and before the first run; any other order is schema-invalid and Word would repair. {detail}\nSerialized XML:\n{xml}"
        );
    }
    assert!(
        xml.contains("urn:schemas-microsoft-com:office:office"),
        "MS-OI29500 §2.1.187: Word requires this exact uri on the smartTagPr/attr; the re-nested wrapper must preserve the opaque property child verbatim. Serialized XML:\n{xml}"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA Annex A: a correctly ordered CT_SmartTagRun (smartTagPr before runs) is schema-valid and opens without repair. validate issues: {detail}"
    );
}

/// ECMA §17.5.1.3/.7/.8, Annex A CT_CustomXmlRun/CT_CustomXmlPr — on re-nest the
/// serializer must emit customXmlPr before runs, and placeholder before attr.
#[test]
fn customxmlpr_renest_placeholder_then_attr_before_runs() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Hello </w:t></w:r><w:customXml w:uri="urn:x" w:element="name"><w:customXmlPr><w:placeholder w:val="[name]"/><w:attr w:uri="urn:x" w:name="status" w:val="draft"/></w:customXmlPr><w:r><w:t>World</w:t></w:r></w:customXml></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // xmlRegex `<w:customXmlPr><w:placeholder\b[^>]*/><w:attr\b` — placeholder
    // must precede attr inside customXmlPr.
    if let Err(detail) = ordered_contains(&xml, &["<w:customXmlPr>", "<w:placeholder", "<w:attr"]) {
        panic!(
            "ECMA Annex A CT_CustomXmlPr = (placeholder?, attr*): the re-nest serializer must emit placeholder before attr; reversing the order is schema-invalid. {detail}\nSerialized XML:\n{xml}"
        );
    }
    // xmlRegex `<w:customXml\b[^>]*><w:customXmlPr>.*?</w:customXmlPr><w:r>` —
    // customXmlPr must precede the wrapped run content.
    if let Err(detail) = ordered_contains(
        &xml,
        &[
            "<w:customXml",
            "<w:customXmlPr>",
            "</w:customXmlPr>",
            "<w:r>",
        ],
    ) {
        panic!(
            "ECMA Annex A CT_CustomXmlRun = (customXmlPr?, EG_PContent*): the property child must precede the wrapped run content on re-nest. {detail}\nSerialized XML:\n{xml}"
        );
    }
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA §17.5.1.3/.7: a correctly ordered customXml run wrapper (customXmlPr leading, placeholder before attr) is schema-valid and opens without repair. validate issues: {detail}"
    );
}

/// ECMA §17.5.1.6/.7, §A.1 CT_CustomXmlBlock — in a block-level customXml the
/// customXmlPr child must serialize FIRST, before the wrapped block content.
#[test]
fn custom_xml_pr_precedes_block_content() {
    let body = r#"<w:customXml w:uri="urn:ex" w:element="address"><w:customXmlPr><w:attr w:uri="urn:ex" w:name="status" w:val="draft"/></w:customXmlPr><w:p><w:r><w:t>Body</w:t></w:r></w:p></w:customXml><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA §A.1 CT_CustomXmlBlock (customXmlPr?, EG_ContentBlockContent*): a block-level customXml with customXmlPr ahead of its wrapped paragraph is conformant and must open without repair. validate issues: {detail}"
    );
    let xml = reserialize(&b);
    // xmlRegex `<w:customXml[^>]*>\s*<w:customXmlPr>.*?</w:customXmlPr>\s*<w:p>`
    // — customXmlPr must be the first child, immediately before the paragraph.
    if let Err(d) = ordered_contains(
        &xml,
        &[
            "<w:customXml",
            "<w:customXmlPr>",
            "</w:customXmlPr>",
            "<w:p>",
        ],
    ) {
        panic!(
            "ECMA §A.1 CT_CustomXmlBlock: the serializer must emit customXmlPr as the first child, immediately before the wrapped paragraph. {d}\nSerialized XML:\n{xml}"
        );
    }
}

/// ECMA §17.5.1.9 — smart tags NEST: EG_PContent admits smartTag inside
/// smartTag, and Word's own emission wraps a whole place name in
/// `element="place"` with `element="PlaceName"`/`element="PlaceType"`
/// children spanning several runs. The transparent-wrapper decomposition
/// must reconstruct the SAME nesting on round-trip. Pairing open/close
/// markers by element name alone folds open-with-open for nested
/// same-name wrappers and flattens the structure (wild witness: a school
/// letterhead paragraph whose place>PlaceName nesting was rebuilt as flat
/// siblings with the wrong spans).
#[test]
fn nested_same_name_smarttags_roundtrip_with_nesting_intact() {
    let body = concat!(
        r#"<w:p>"#,
        r#"<w:smartTag w:uri="urn:schemas-microsoft-com:office:smarttags" w:element="place">"#,
        r#"<w:smartTag w:uri="urn:schemas-microsoft-com:office:smarttags" w:element="PlaceName">"#,
        r#"<w:r><w:t>Bolivar-Richburg</w:t></w:r></w:smartTag>"#,
        r#"<w:r><w:t xml:space="preserve"> </w:t></w:r>"#,
        r#"<w:smartTag w:uri="urn:schemas-microsoft-com:office:smarttags" w:element="PlaceType">"#,
        r#"<w:r><w:t>School</w:t></w:r></w:smartTag>"#,
        r#"</w:smartTag>"#,
        r#"</w:p><w:sectPr/>"#,
    );
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    let root = xmltree::Element::parse(std::io::Cursor::new(xml.as_bytes())).expect("parse xml");
    let body_el = root.get_child("body").expect("body");
    let para = body_el.get_child("p").expect("paragraph");
    let top_tags: Vec<&xmltree::Element> = para
        .children
        .iter()
        .filter_map(|c| match c {
            xmltree::XMLNode::Element(e) if e.name == "smartTag" => Some(e),
            _ => None,
        })
        .collect();
    assert_eq!(
        top_tags.len(),
        1,
        "one OUTER place smartTag, not flattened siblings: {xml}"
    );
    let outer = top_tags[0];
    let attr = |e: &xmltree::Element, name: &str| -> Option<String> {
        e.attributes
            .iter()
            .find(|(k, _)| k.local_name == name)
            .map(|(_, v)| v.clone())
    };
    assert_eq!(attr(outer, "element").as_deref(), Some("place"), "{xml}");
    let inner: Vec<String> = outer
        .children
        .iter()
        .filter_map(|c| match c {
            xmltree::XMLNode::Element(e) if e.name == "smartTag" => attr(e, "element"),
            _ => None,
        })
        .collect();
    assert_eq!(
        inner,
        vec!["PlaceName".to_string(), "PlaceType".to_string()],
        "both inner wrappers stay nested inside place, in order: {xml}"
    );

    // Fixpoint: a second round-trip must not restructure further.
    let again = reserialize(&{
        let doc = Document::parse(&b).expect("parse");
        doc.serialize(&stemma::ExportOptions::default())
            .expect("serialize")
    });
    assert_eq!(xml, again, "wrapper reconstruction must be a fixpoint");

    let (ok, detail) = opens_clean(&b);
    assert!(ok, "nested smart tags are valid WML: {detail}");
}
